import React, { memo } from "react";
import { Link } from "react-router-dom";
import { ShieldCheck, Wrench, BatteryCharging, Sparkles, CheckCircle2, MapPin } from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle } from "./src/components/ui/card";

const Section = ({ id, children, className = "" }) => (
  <section id={id} className={`mx-auto w-full max-w-7xl px-6 md:px-10 ${className}`}>{children}</section>
);

const Feature = ({ icon: Icon, title, children }) => (
  <Card className="rounded-3xl border-white/40 bg-white/80 shadow-xl backdrop-blur dark:bg-slate-900/70 dark:border-slate-800 hover:shadow-2xl hover:scale-105 transition-all duration-300 group relative overflow-hidden">
    <div className="absolute inset-0 bg-gradient-to-br from-[#0F62FE]/5 via-transparent to-[#0FB5AF]/5 opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
    <CardHeader className="flex flex-row items-center gap-3 pb-2 relative z-10">
      <div className="p-3 rounded-xl bg-gradient-to-br from-[#0F62FE] via-[#0FB5AF] to-[#004E92] text-white shadow-lg group-hover:shadow-xl group-hover:scale-110 transition-all duration-300 relative">
        <Icon className="h-6 w-6" />
        <div className="absolute inset-0 rounded-xl bg-white/20 opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
      </div>
      <CardTitle className="text-lg font-bold tracking-tight text-slate-900 dark:text-slate-100 group-hover:text-[#0F62FE] dark:group-hover:text-[#0FB5AF] transition-colors duration-300">{title}</CardTitle>
    </CardHeader>
    <CardContent className="text-slate-800 dark:text-slate-300 text-sm leading-relaxed relative z-10">
      {children}
    </CardContent>
  </Card>
);

const ServicesSection = memo(() => {
  return (
    <Section id="services" className="py-12">
      <Card className="mx-auto max-w-6xl rounded-3xl border-white/40 bg-white/80 shadow-xl backdrop-blur dark:bg-slate-900/70 dark:border-slate-800">
        <CardHeader>
          <CardTitle asChild className="text-3xl md:text-4xl font-bold tracking-tight text-slate-900 dark:text-slate-100">
            <h2>Meie autoteenused Tallinnas</h2>
          </CardTitle>
          <h2 className="text-xl md:text-2xl font-medium tracking-tight text-slate-900 dark:text-slate-100 mt-2">
            Autodiagnostika Tallinnas
          </h2>
          <h2 className="text-xl md:text-2xl font-medium tracking-tight text-slate-900 dark:text-slate-100 mt-1">
            Rehvitööd ja rataste tasakaalustamine Tallinnas
          </h2>
          <h2 className="text-xl md:text-2xl font-medium tracking-tight text-slate-900 dark:text-slate-100 mt-1">
            Autopesu ja premium-detailing Tallinnas
          </h2>
          <h2 className="text-xl md:text-2xl font-medium tracking-tight text-slate-900 dark:text-slate-100 mt-1">
            Mootoritööd ja elektrisüsteemide remont
          </h2>
          <h2 className="text-xl md:text-2xl font-medium tracking-tight text-slate-900 dark:text-slate-100 mt-1">
            Pidurid ja veermik — kontroll ja hooldus
          </h2>
          <p className="mt-3 max-w-2xl text-slate-800 dark:text-slate-300">Pidurid, veermik, mootor, elekter ja keerukate vigade leidmine — me ei karda keerulisi juhtumeid. Autohooldus Tallinnas, autodiagnostika, rehvitööd ja autopesu Tallinnas. Meie rehvitööd Tallinnas tagavad, et su auto on valmis igaks ilmastikuks, ning autopesu teenus Tallinnas muudab su sõiduki säravaks. Vali meie autodiagnostika teenus, et vältida ootamatuid remondikulusid. Pakume ka mootori remont Tallinnas, elektritööd Tallinnas ja veermiku remont Tallinnas.</p>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            <Link to="/piduritooed-tallinnas" className="block group">
              <Feature icon={ShieldCheck} title="Pidurid & veermik">
                Remont ja hooldus: klotsid, kettad, pidurisadulad, amordid, liigendite vahetus — OE‑ või premium‑komponendid.
              </Feature>
            </Link>
            <Link to="/mootoritooed-tallinnas" className="block group">
              <Feature icon={Wrench} title="Mootoritööd">
                Hooldustest kuni põhjaliku remontini. Täpne mõõdistus, pöördemomendi kontroll, tihendite vahetus ja ajastustööd.
              </Feature>
            </Link>
            <Link to="/elektritooed-tallinnas" className="block group">
              <Feature icon={BatteryCharging} title="Elektri‑ ja diagnostika">
                CAN‑buss, andurid, juhtplokid. Süsteemne veaotsing, logimine ja kinnitustestid.
              </Feature>
            </Link>
            <Link to="/veermiku-remont-tallinnas" className="block group">
              <Feature icon={Sparkles} title="Detailihool & viimistlus">
                Puhastus ja kaitse stuudio standardi järgi: puhas, turvaline, kontrollitud.
              </Feature>
            </Link>
            <div className="group">
              <Feature icon={CheckCircle2} title="Kvaliteedikontroll">
                Tööjärgne ülevaatus kontrollnimekirja alusel. Proovisõit ja ülevaatus.
              </Feature>
            </div>
            <div className="group">
              <Feature icon={MapPin} title="Üks külaskäik — mitu lahendust">
                Planeerime töö nii, et ühe korraga saaks tehtud võimalikult palju.
              </Feature>
            </div>
          </div>
        </CardContent>
      </Card>
    </Section>
  );
});

ServicesSection.displayName = 'ServicesSection';

export default ServicesSection;
